-- Plain HTTP video manifests are blocked as mixed content on the HTTPS app.
UPDATE public.tv_channels
SET is_active = FALSE
WHERE is_active = TRUE
  AND stream_url LIKE 'http://%';

UPDATE public.tv_stream_sources
SET is_active = FALSE
WHERE is_active = TRUE
  AND url LIKE 'http://%';

